mapper.select:
SELECT id, display_name, email, avatar_url, created_at, updated_at
FROM user_profile
WHERE id = #{id}

mapper.update:
UPDATE user_profile
SET display_name = #{displayName},
    email = #{email},
    avatar_url = #{avatarUrl},
    updated_at = #{updatedAt}
WHERE id = #{id, typeHandler=com.grace.platform.shared.infrastructure.persistence.typehandler.UserProfileIdTypeHandler}
